INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('real-estate-moex-00961', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關租賃契約之敘述，何者錯誤？ 租賃關係存續中，出租人未使租賃物合於約定使用收益狀態，致承租人未達租賃目的者，承租人 得拒絕給付租金 出租人將已交付承租人之租賃物的所有權讓與他人，承租人與受讓人間仍須另立租賃契約始發生 租賃關係 定有期限之租賃契約，當事人約定得提前終止者，於終止契約前應先期通知 租賃契約經公證並附有逕受強制執行條款者，當承租人有不付租金、租期屆滿拒不搬遷，或房東 不返還押租金時，當事人可直接申請強制執行', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 36, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00962', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關抵押權之敘述，何者正確？ 以抵押權擔保之債權請求權，雖經時效消滅，債權人仍得於時效完成後5年內實行抵押權 以建築物為抵押者，其附加部分亦為抵押權效力所及，應一律併付拍賣 抵押權人聲請查封抵押物，惟該執行名義嗣後經抗告法院裁定予以廢棄確定時，抵押人可依法請 求財產上及非財產上損害賠償 抵押權人於債權清償期屆滿後，為受清償，不得訂立契約取得抵押物之所有權', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00963', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關契約解除之敘述，何者錯誤？ 契約解除時，當事人雙方負回復原狀之義務 解除權之行使，不妨礙損害賠償之請求 房屋買賣契約解除時，原買受人已支出之裝潢費用均得請求出賣人返還 解除權之行使，得以送達訴狀繕本予他方當事人之方法為之', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 38, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00964', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關相鄰關係之敘述，何者錯誤？ 聲響之侵入係偶發、輕微或依地方習慣認為相當者，彼此仍應於合理程度範圍內忍受，不得請求 損害賠償 相鄰關係重在不動產利用人間權利義務關係之調和，不以各該不動產相互緊鄰為必要 土地所有人拆除舊建物時，致相鄰樓房發生傾斜、龜裂等，應依民法第 184條第2項負損害賠償 責任 土地所有人非因故意或重大過失建築房屋逾越疆界者，鄰地所有人無論何時均得提出異議，請求 移去或變更其建築物', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 39, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00965', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關人格權之敘述，何者錯誤？ 姓名乃用以區別人己之一種語言標誌，將人個別化，以確定其人之同一性 法人在法令限制與性質範圍內，亦享有人格權 公司名稱用以識別企業之主體性，此時姓名權等於商標權 針對無涉公益之報導，若不當揭載足資識別當事人資料，侵害其名譽權者，得依民法第18條請求 排除侵害', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00966', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'essay', '甲乙為多年好友，甲於民國（下同）85 年 1 月 1 日向乙借款 500 萬元，未約定清
償期，並於同日以A地設定500萬元普通抵押權予乙。詎甲於104年10月31日死
亡，甲的唯一繼承人丙於105年1月20日為辦理遺產稅申報而調取A地土地謄本，
始發現 A 地上有乙之 500 萬元普通抵押權，丙以該借款債權已逾消滅時效，且該抵
押權亦已消滅為由，向乙起訴請求塗銷抵押權。問：丙之起訴有無理由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00967', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'essay', '甲為 A 公寓 5 樓之區分所有權人，其將該公寓頂樓搭建鐵皮屋並隔成三間房間使
用（未辦建物所有權第一次登記），長期以來 A 公寓其他區分所有權人並無反對
意思，今甲將該 5 樓及頂樓鐵皮屋出售予乙。問：甲於 A 公寓頂樓搭建鐵皮屋之
使用權源為何？（12分）甲乙間就該鐵皮屋之買賣契約是否有效？（13分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00968', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關民法的法源，民法第 1 條規定「民事，法律所未規定者，依習慣；無習慣者，依法理。」下列敘述 何者正確？', '["民間「洗門風」的習慣，即是該條所稱之「習慣」", "此之「習慣」，係專指習慣法而言", "憲法關於人民之權利義務的規定，是該條所稱之法律", "條約是規範國家間權利義務之協定，絕非是民法法源之一"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00969', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '依民法之規定，下列何種非屬法定要式行為？', '["兩願離婚", "買賣契約", "所有權移轉", "社團章程之訂定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00970', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關財產權之描述，下列敘述何者正確？', '["債權是請求權，所以只能約定由特定人請求另一特定人為一定作為，但不能約定不作為", "債權具有相對性，所以當出賣人一屋先後兩賣時，前後買賣契約皆為有效", "基於契約自由原則，當事人可以自由創設物權種類，不受限制", "債權給付之內容，以有財產價格者為限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00971', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關人格權之敘述，下列何者錯誤？', '["自由不得限制", "行為能力不得拋棄", "人格權具有專屬性", "當人格權受侵害時，得請求法院除去其侵害"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00972', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '30歲的甲患有精神疾病，並受監護宣告。某日，甲於精神狀況良好時，單獨到乙電信公司購買手機一支。 試問甲乙間之買賣契約，其效力為何？', '["有效", "無效", "得撤銷", "效力未定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00973', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲誤認為好友所贈與之戒指，乃鍍金之假鑽戒，遂將該戒指以 5 百元之價格賣給乙，並已交付。甲事後 得知此乃真金真鑽之戒指，且價值5萬元。有關此法律行為之敘述，下列何者正確？', '["甲乙間之買賣契約無效，但物權行為有效", "甲乙間之買賣契約有效，但物權行為無效", "甲乙間之買賣契約得撤銷，但物權行為無效", "甲乙間之買賣契約得撤銷，但物權行為有效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00974', 'real-estate', 'real-estate-moex-105-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關法律行為之標的，下列敘述何者正確？', '["甲乙約定以火星上岩石為贈與標的物，該契約有效", "甲乙約定故宮翠玉白菜為買賣標的物，該契約有效", "甲乙約定甲需於1日內完成環島健走行程，該契約有效", "甲乙婚前協議約定，婚後任一方若有出軌行為，必須支付對方新臺幣100萬元賠償費，該契約有效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "fcbd3c9e394e", "answer_pdf_sha1": "33c2bced15a8", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
